export function resolveProductFilename(productName: string): string | null {
  const key = productName.toLowerCase().trim();
  if (productNameMap[key]) return productNameMap[key];
  const collapsed = key.replace(/\s{2,}/g, ' ');
  if (productNameMap[collapsed]) return productNameMap[collapsed];
  const noSpace = key.replace(/\s+/g, '');
  if (productNameMap[noSpace]) return productNameMap[noSpace];
  return null;
}

